external_knowledge:
- "sails the boat of employment" refers to the individuals categorized under 'Employment';
- "gender sails the boat" metaphorically refers to the gender of the employed individuals;
- "number of sailors" refers to the count of employed individuals for each gender and each year.

- Characteristic_id = 1 might refer to a specific labor force characteristic such as full-time employment;
- Gender_id = 3 might denote a specific gender category, such as non-binary or other categories not typically male or female;
- Geo_id = 4 could represent a particular geographical unit, such as a state or a region;
- Naics_id = 5 refers to a specific NAICS (North American Industry Classification System) code, indicating a specific industry;
- Source_id = 6 indicates the data has been collected from a specific data source or survey.

sql:
SELECT data_id, ref_date, geo_id, characteristic_id, naics_id, gender_id, value, source_id, version, created_at, updated_at 
FROM labor_force_data
WHERE value = (SELECT MAX(value) FROM labor_force_data);

SELECT MAX(value)
FROM labor_force_data
WHERE source_id = 1;

SELECT naics_id, naics_code
FROM naics_codes
WHERE naics_id = 1;

SELECT geo_id, geo_name, geo_type, geo_code
FROM geographies
WHERE parent_geo_id IS NULL;

SELECT geo_name, geo_code
FROM geographies
WHERE geo_id = (SELECT geo_id FROM labor_force_data WHERE data_id = 1);

SELECT lfd.value, g.gender_label
FROM labor_force_data AS lfd
JOIN genders AS g ON lfd.gender_id = g.gender_id;

SELECT visualization_name, visualization_type, data_source 
FROM visualizations 
WHERE visualization_id = 1;

SELECT value 
FROM labor_force_data 
WHERE characteristic_id != 0;
